package com.ecoPedal.backend.entity;import jakarta.persistence.*;import jakarta.validation.constraints.NotBlank;import lombok.*;import java.util.ArrayList;import java.util.List;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Entity@Table(name = "station")public class Station {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @NotBlank    @Column(nullable = false)    private String nom;    @Column(nullable = false)    private String adresse;    @Column(nullable = false)    private Integer capacite;    @OneToMany(mappedBy = "station")    private List<Velo> veloList = new ArrayList<>();    @OneToMany(mappedBy = "station")    private List<Reservation> reservationList = new ArrayList<>();    @OneToMany(mappedBy = "station")    private List<Location> locationList = new ArrayList<>();}